// [G3] paso 2: Hash PII (SHA-256) + build Meta CAPI payload
const crypto = require('crypto');

const body = $input.first().json.body || $input.first().json;

function sha256(str) {
  if (!str) return '';
  return crypto.createHash('sha256').update(str.toString()).digest('hex');
}

// Email: lowercase + trim, then hash
function hashEmail(email) {
  if (!email) return null;
  return sha256(email.toString().toLowerCase().trim());
}

// Phone: strip non-digits (NO leading +), then hash
function hashPhone(phone) {
  if (!phone) return null;
  const digits = phone.toString().replace(/\D/g, '');
  if (!digits) return null;
  return sha256(digits);
}

// External ID: trim (preserve case), then hash
function hashExternalId(extId) {
  if (!extId) return null;
  return sha256(extId.toString().trim());
}

const userData = body.user_data || {};
const customData = body.custom_data || {};

const metaUserData = {};
if (userData.email) metaUserData.em = [hashEmail(userData.email)];
if (userData.phone_e164) metaUserData.ph = [hashPhone(userData.phone_e164)];
if (userData.external_id) metaUserData.external_id = [hashExternalId(userData.external_id)];
if (userData.fbc) metaUserData.fbc = userData.fbc;
if (userData.fbp) metaUserData.fbp = userData.fbp;
if (userData.client_ip_address) metaUserData.client_ip_address = userData.client_ip_address;
if (userData.client_user_agent) metaUserData.client_user_agent = userData.client_user_agent;

const metaEvent = {
  event_name: body.event_name,
  event_time: body.event_time || Math.floor(Date.now() / 1000),
  event_id: body.event_id,
  action_source: body.action_source || 'website',
  user_data: metaUserData,
};
if (body.event_source_url) metaEvent.event_source_url = body.event_source_url;
if (Object.keys(customData).length > 0) metaEvent.custom_data = customData;

const payload = {
  data: [metaEvent],
};

// test_event_code: solo si env var presente y non-empty
if ($env.META_TEST_EVENT_CODE && $env.META_TEST_EVENT_CODE.trim() !== '') {
  payload.test_event_code = $env.META_TEST_EVENT_CODE.trim();
}

return [{ json: { _meta_payload: payload, _event_id: body.event_id, _event_name: body.event_name } }];

// [G3] paso 4: Build response al ERP
const metaResponse = $input.first().json;
const original = $('Hash PII + Build Meta Payload').first().json;

const eventsReceived = metaResponse.events_received || 0;
const fbtraceId = metaResponse.fbtrace_id || null;
const messages = metaResponse.messages || [];

return [{ json: {
  ok: eventsReceived === 1 && messages.length === 0,
  events_received: eventsReceived,
  fbtrace_id: fbtraceId,
  event_id: original._event_id,
  event_name: original._event_name,
  meta_messages: messages,
} }];
